import type { CareerQuestion } from "./social-worker-questions";

export const socialWorkerQuestionsBatch16: CareerQuestion[] = [
  { id: "sw-776", stem: "A social worker is conducting a suicide risk assessment. Which factor represents the HIGHEST level of acute risk?", options: ["Passive death wishes", "A specific plan with access to lethal means, a stated intention to act, recent rehearsal behavior, and lack of protective factors such as reasons for living or social support", "General feelings of hopelessness", "Family history of depression"], correctIndex: 1, rationale: "Acute suicide risk increases with: specific plan, access to means, stated intent, rehearsal behavior (practicing, writing notes), giving away possessions, sudden calm after depression, substance intoxication, recent loss, and absence of protective factors. A comprehensive assessment evaluates: ideation, plan, intent, means access, timeline, history of attempts, protective factors, and warning signs.", difficulty: 3, category: "Crisis Intervention", topic: "Acute Suicide Risk", questionType: "CASE_VIGNETTE" },
  { id: "sw-777", stem: "What is 'countertransference' in clinical social work?", options: ["The client's feelings toward the therapist", "The therapist's emotional reactions to the client that are influenced by the therapist's own personal history, unresolved conflicts, or unconscious processes, which can either help or hinder the therapeutic process", "A billing arrangement", "A type of referral"], correctIndex: 1, rationale: "Countertransference includes all emotional reactions the therapist has toward the client. It can be: complementary (reacting to the client's transference), concordant (identifying with the client's experience), or reactive (triggered by the therapist's own unresolved issues). Self-awareness through supervision and personal therapy helps clinicians use countertransference productively rather than acting it out.", difficulty: 2, category: "Clinical Practice", topic: "Countertransference", questionType: "CASE_VIGNETTE" },
  { id: "sw-778", stem: "The social work concept of 'empowerment' BEST refers to:", options: ["Giving power to clients", "A process through which individuals, families, and communities gain the knowledge, skills, resources, and confidence to take control of their own lives, advocate for their needs, and influence systems that affect them", "Making decisions for vulnerable clients", "Professional authority over clients"], correctIndex: 1, rationale: "Empowerment is a process, not something given. It involves: building critical consciousness, developing skills and competencies, accessing resources, strengthening self-efficacy, connecting to collective action, and challenging oppressive structures. Social workers facilitate empowerment by: sharing information, building on strengths, supporting skill development, reducing barriers, and promoting client participation in decision-making.", difficulty: 1, category: "Community Practice & Advocacy", topic: "Empowerment", questionType: "MCQ" },
  { id: "sw-779", stem: "What is 'solution-focused brief therapy' (SFBT) and its key techniques?", options: ["A long-term psychodynamic approach", "A strengths-based, goal-oriented therapy that focuses on solutions rather than problems, using techniques like the miracle question, scaling questions, exception finding, and coping questions", "A medication-based treatment", "A crisis-only intervention"], correctIndex: 1, rationale: "SFBT (de Shazer, Berg) focuses on solutions rather than problems. Key techniques: miracle question ('If a miracle happened tonight...'), scaling questions (rating progress 1-10), exception finding (times the problem didn't occur), coping questions ('How do you manage?'), compliments, and between-session tasks. Assumes: clients have resources to change, small changes lead to larger ones, and focusing on what works is more productive than analyzing problems.", difficulty: 2, category: "Clinical Practice", topic: "SFBT", questionType: "CASE_VIGNETTE" },
  { id: "sw-780", stem: "A social worker is assessing a client for substance use disorder. The DSM-5 criteria include:", options: ["Only physical dependence", "A problematic pattern of use leading to significant impairment or distress with 11 possible criteria including impaired control, social impairment, risky use, and pharmacological indicators, categorized as mild (2-3), moderate (4-5), or severe (6+)", "Only illegal substance use", "Any alcohol consumption"], correctIndex: 1, rationale: "DSM-5 substance use disorder criteria: impaired control (using more/longer than intended, unsuccessful efforts to cut down, craving, excessive time using), social impairment (failure to fulfill obligations, continued use despite social problems, giving up activities), risky use (use in hazardous situations, continued use despite physical/psychological problems), pharmacological (tolerance, withdrawal). Severity: mild (2-3), moderate (4-5), severe (6+).", difficulty: 2, category: "Addictions & Substance Use", topic: "SUD Criteria", questionType: "CASE_VIGNETTE" },
  { id: "sw-781", stem: "What is 'therapeutic use of self' in social work?", options: ["Self-disclosure about personal problems", "The purposeful use of one's personality, values, professional skills, and self-awareness within the therapeutic relationship to promote client growth, while maintaining appropriate professional boundaries", "Befriending clients", "Using intuition instead of evidence"], correctIndex: 1, rationale: "Therapeutic use of self involves: genuine engagement, empathy, self-awareness, appropriate vulnerability, professional boundaries, cultural sensitivity, and purposeful relationship building. It requires: ongoing self-reflection, supervision, understanding one's own biases and triggers, and ability to manage one's reactions in service of the client's goals. It is a defining feature of social work practice.", difficulty: 2, category: "Communication & Interviewing", topic: "Therapeutic Use of Self", questionType: "CASE_VIGNETTE" },
  { id: "sw-782", stem: "What is 'attachment theory' and its relevance to social work?", options: ["Only relevant to infants", "A theory describing how early caregiving relationships shape internal working models that influence relationship patterns, emotion regulation, and sense of self throughout the lifespan, with implications for assessment and treatment across all populations", "A theory about physical bonding", "Only relevant to adoption"], correctIndex: 1, rationale: "Attachment theory (Bowlby, Ainsworth) describes four patterns: secure, anxious-ambivalent, avoidant, and disorganized. These patterns, formed in early caregiving relationships, create internal working models that influence: relationship expectations, emotion regulation, help-seeking behavior, parenting, and response to loss. Social workers use attachment theory in: child welfare assessments, trauma treatment, couples therapy, and understanding therapeutic alliance.", difficulty: 2, category: "Child & Family Services", topic: "Attachment Theory", questionType: "CASE_VIGNETTE" },
  { id: "sw-783", stem: "A social worker is working with an undocumented immigrant family. Ethical considerations include:", options: ["Reporting to immigration authorities", "Providing services regardless of immigration status, maintaining confidentiality, understanding immigration-related fear and trauma, connecting to culturally competent resources, and advocating for the family's rights and access to services", "Refusing to provide services", "Requiring documentation before treatment"], correctIndex: 1, rationale: "The NASW Code of Ethics requires serving all clients regardless of immigration status. Ethical obligations include: confidentiality (immigration status is protected information), cultural competence, understanding the impact of immigration policy on mental health, connecting to immigration legal services, addressing fear and trauma, advocating for access to services, and not serving as immigration enforcement agents.", difficulty: 2, category: "Ethics & Professional Boundaries", topic: "Undocumented Clients", questionType: "ETHICS_SCENARIO" },
  { id: "sw-784", stem: "What is 'psychoeducation' and when is it used in social work practice?", options: ["Traditional classroom education", "An evidence-based therapeutic intervention that provides clients and families with information about mental health conditions, coping strategies, treatment options, and skills to manage symptoms and improve functioning", "Only providing pamphlets", "Academic counseling"], correctIndex: 1, rationale: "Psychoeducation provides: information about diagnoses and symptoms, normalization of experiences, coping skills, relapse prevention strategies, medication information, communication skills, and problem-solving strategies. It is used in: individual therapy, family therapy (family psychoeducation for schizophrenia has strong evidence), group settings, and community mental health. It empowers clients as active participants in their treatment.", difficulty: 1, category: "Mental Health & Psychopathology", topic: "Psychoeducation", questionType: "CASE_VIGNETTE" },
  { id: "sw-785", stem: "What is the difference between 'confidentiality' and 'privilege' in social work?", options: ["They are identical concepts", "Confidentiality is the ethical obligation not to disclose client information without consent, while privilege is a legal right that protects client communications from being disclosed in court proceedings, and its scope varies by jurisdiction", "Privilege is broader than confidentiality", "Neither applies to social workers"], correctIndex: 1, rationale: "Confidentiality is the ethical duty to protect client information (NASW Code of Ethics). Privilege is a legal concept that protects certain communications from court disclosure—it belongs to the client, not the social worker, and varies by state. Privilege may not exist in all jurisdictions for social workers. Both have exceptions: mandated reporting, duty to warn, court orders. Understanding the distinction is essential for ethical and legal practice.", difficulty: 2, category: "Documentation & Record Keeping", topic: "Confidentiality vs Privilege", questionType: "MCQ" },
  { id: "sw-786", stem: "The Family and Medical Leave Act (FMLA) provides eligible employees with:", options: ["Paid family leave", "Up to 12 weeks of unpaid, job-protected leave per year for specified family and medical reasons, including birth or adoption of a child, serious health condition of the employee or family member, and qualifying military exigencies", "Unlimited leave time", "Leave only for the employee's own illness"], correctIndex: 1, rationale: "FMLA provides: up to 12 weeks unpaid leave, job protection (same or equivalent position), continued health insurance. Qualifying reasons: birth/adoption, serious health condition (employee or spouse/child/parent), qualifying military exigency. Eligibility: employed 12+ months, 1,250+ hours worked, employer has 50+ employees. Social workers help clients understand and access FMLA protections.", difficulty: 2, category: "Legislation & Policy Frameworks", topic: "FMLA", questionType: "APPLIED_ETHICS" },
  { id: "sw-787", stem: "What is 'cultural formulation' in clinical assessment?", options: ["Ignoring cultural factors", "A systematic assessment of how cultural factors influence the client's presentation, illness experience, help-seeking behavior, therapeutic relationship, and treatment expectations, as outlined in the DSM-5 Cultural Formulation Interview", "Only noting the client's ethnicity", "Applying Western norms universally"], correctIndex: 1, rationale: "The DSM-5 Cultural Formulation Interview assesses: cultural identity (ethnic, religious, linguistic), cultural conceptualization of distress (how culture shapes understanding of the problem), psychosocial stressors and cultural features of vulnerability/resilience, cultural features of the therapeutic relationship, and cultural assessment for diagnosis and care. This prevents misdiagnosis and ensures culturally responsive treatment.", difficulty: 2, category: "Diversity, Equity & Inclusion", topic: "Cultural Formulation", questionType: "CASE_VIGNETTE" },
  { id: "sw-788", stem: "What are 'process recordings' used for in social work education and supervision?", options: ["Audio recordings of sessions", "Detailed written accounts of a therapy session including the social worker's thoughts, feelings, and observations alongside the dialogue, used as a teaching and supervisory tool to develop clinical skills and self-awareness", "Administrative billing records", "Client satisfaction surveys"], correctIndex: 1, rationale: "Process recordings typically include three columns: what was said (dialogue), what the worker was thinking/feeling (internal responses), and supervisor analysis. They help: develop self-awareness, identify therapeutic patterns, examine use of skills, explore countertransference, practice conceptualization, and receive detailed supervision feedback. They are a core training tool in social work education.", difficulty: 1, category: "Documentation & Record Keeping", topic: "Process Recordings", questionType: "MCQ" },
  { id: "sw-789", stem: "A social worker is facilitating a psychoeducation group for families of individuals with schizophrenia. Key content includes:", options: ["Blaming families for the illness", "Information about schizophrenia symptoms, medication management, recognizing early warning signs of relapse, communication skills, stress management, problem-solving, and community resources for ongoing support", "Only medication information", "Discouraging family involvement in treatment"], correctIndex: 1, rationale: "Family psychoeducation for schizophrenia has strong evidence (McFarlane, Mueser). Content includes: understanding schizophrenia (biological basis, symptoms, course), medication management, recognizing prodromal signs, reducing expressed emotion, communication skills, problem-solving, stress management, self-care for caregivers, crisis planning, and community resources. It significantly reduces relapse rates and improves family functioning.", difficulty: 2, category: "Group Work", topic: "Family Psychoeducation", questionType: "MCQ" },
  { id: "sw-790", stem: "What is 'ageism' and how does it affect older adults' access to healthcare?", options: ["A natural result of aging", "Systematic stereotyping, prejudice, and discrimination against people based on age, which leads to under-treatment of pain, under-diagnosis of depression, reduced access to preventive care, and assumptions that symptoms are 'just aging'", "Respect for elders", "Only affects employment"], correctIndex: 1, rationale: "Ageism in healthcare manifests as: attributing treatable symptoms to normal aging, under-treating pain, under-diagnosing depression and substance use, providing less aggressive treatment for cancer, excluding older adults from clinical trials, patronizing communication, and reducing access to mental health services. Social workers combat ageism by: advocating for appropriate treatment, challenging assumptions, and empowering older adults.", difficulty: 2, category: "Gerontology", topic: "Ageism in Healthcare", questionType: "CASE_VIGNETTE" },
  { id: "sw-791", stem: "What is the difference between 'bullying' and 'conflict' in school settings?", options: ["They are the same thing", "Bullying involves a power imbalance with intentional, repeated aggressive behavior, while conflict occurs between individuals of relatively equal power and does not involve the same pattern of dominance and victimization", "Bullying only involves physical aggression", "Conflict is always more serious"], correctIndex: 1, rationale: "Key differences: bullying involves power imbalance, intent to harm, repetition, and one-sided aggression; conflict involves relatively equal power, mutual disagreement, and can be constructive. This distinction matters for intervention: bullying requires protection of the target and accountability for the bully, while conflict benefits from mediation and skill-building. Mediation should not be used for bullying situations.", difficulty: 2, category: "School Social Work", topic: "Bullying vs Conflict", questionType: "MCQ" },
  { id: "sw-792", stem: "What is 'mandatory reporting' and what triggers the obligation?", options: ["Reporting all client disclosures", "A legal requirement that designated professionals, including social workers, must report to appropriate authorities when they have reasonable suspicion of child abuse/neglect, elder abuse, or vulnerable adult abuse, regardless of client wishes", "Only reporting confirmed abuse", "Voluntary reporting of suspected abuse"], correctIndex: 1, rationale: "Mandatory reporting is triggered by reasonable suspicion, not certainty. Key elements: it is a legal obligation (failure to report can result in criminal charges), it overrides confidentiality, the reporter is not required to investigate or confirm abuse, reports should be made promptly, reporters are protected from liability when reporting in good faith, and specific reporting requirements vary by jurisdiction.", difficulty: 1, category: "Safeguarding & Vulnerable Populations", topic: "Mandatory Reporting", questionType: "PRIORITIZATION" },
  { id: "sw-793", stem: "How does 'transportation access' function as a social determinant of health?", options: ["It does not affect health", "Lack of reliable transportation creates barriers to healthcare appointments, employment, grocery stores, pharmacies, and social connections, disproportionately affecting rural, elderly, disabled, and low-income populations", "It only affects rural areas", "Transportation is a personal choice"], correctIndex: 1, rationale: "Transportation barriers impact: missed medical appointments, delayed preventive care, inability to fill prescriptions, limited employment options, food insecurity (limited grocery access), social isolation, and inability to access social services. Social workers address transportation by: connecting to medical transportation services, advocating for public transit improvements, coordinating telehealth, and addressing transportation in discharge and care planning.", difficulty: 2, category: "Social Determinants of Health", topic: "Transportation Access", questionType: "MCQ" },
  { id: "sw-794", stem: "What is the role of the social worker in interprofessional education (IPE)?", options: ["Social workers don't participate in IPE", "Bringing the psychosocial perspective, advocacy skills, systems thinking, and person-centered values to collaborative learning experiences where students from different health professions learn about, from, and with each other", "Only teaching social work students", "Administrative coordination only"], correctIndex: 1, rationale: "Social workers contribute to IPE by: sharing psychosocial expertise, modeling person-centered practice, demonstrating advocacy and systems navigation, teaching communication skills, and emphasizing cultural competence. IPE prepares professionals to work in interprofessional teams, improving patient outcomes. Social work's person-in-environment perspective and commitment to social justice offer unique contributions to interprofessional learning.", difficulty: 2, category: "Interdisciplinary Collaboration", topic: "Interprofessional Education", questionType: "MCQ" },
  { id: "sw-795", stem: "What is 'reflective listening' and how does it differ from paraphrasing?", options: ["They are identical techniques", "Reflective listening involves capturing and reflecting back the emotional meaning and underlying feelings of what the client has communicated, while paraphrasing restates the content or facts of what was said", "Reflective listening is passive", "Paraphrasing involves interpretation"], correctIndex: 1, rationale: "Reflective listening goes deeper than paraphrasing: it reflects the emotional content and meaning behind the words. Example: Client: 'I've been doing everything for this family and no one notices.' Paraphrase: 'You've been taking on a lot of responsibilities.' Reflection: 'It sounds like you're feeling unappreciated and exhausted.' Reflective listening conveys deep understanding and validates emotional experience.", difficulty: 2, category: "Communication & Interviewing", topic: "Reflective Listening", questionType: "CASE_VIGNETTE" },
  { id: "sw-796", stem: "An ASWB exam question asks about 'termination' in social work. The social worker should:", options: ["End services abruptly when goals are met", "Plan for termination from the beginning of the relationship, address termination feelings, review progress, consolidate gains, plan for maintaining changes, provide appropriate referrals, and allow adequate time for the ending process", "Avoid discussing termination to prevent anxiety", "Continue services indefinitely"], correctIndex: 1, rationale: "Ethical termination involves: planning from the outset, gradually reducing frequency, reviewing treatment gains, addressing feelings about ending (loss, abandonment, independence), consolidating skills, developing a maintenance plan, providing referrals as needed, and leaving the door open for future contact. Premature termination risks should be addressed throughout treatment.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "Termination", questionType: "MCQ" },
  { id: "sw-797", stem: "What is 'compassion fatigue' and how does it differ from burnout?", options: ["They are the same thing", "Compassion fatigue is the emotional and physical exhaustion from bearing witness to clients' trauma and suffering, with rapid onset, while burnout results from cumulative workplace stressors like excessive workload, with gradual onset", "Compassion fatigue only affects new workers", "Burnout is more severe"], correctIndex: 1, rationale: "Compassion fatigue (Figley): rapid onset, triggered by exposure to clients' trauma, involves secondary traumatic stress symptoms (intrusive thoughts, avoidance, hyperarousal), can affect even satisfied workers. Burnout (Maslach): gradual onset, results from organizational stressors (workload, lack of autonomy, insufficient reward), involves emotional exhaustion, depersonalization, and reduced accomplishment. Both require different interventions.", difficulty: 2, category: "Ethics & Professional Boundaries", topic: "Compassion Fatigue", questionType: "ETHICS_SCENARIO" },
  { id: "sw-798", stem: "What is 'grounding' and when is it used in clinical practice?", options: ["A punishment technique", "A set of techniques that help clients reconnect to the present moment when experiencing dissociation, flashbacks, panic, or emotional overwhelm, using sensory awareness to anchor attention to the here and now", "Only a mindfulness practice", "A technique only for children"], correctIndex: 1, rationale: "Grounding techniques bring awareness to the present moment. Types: physical (feet on floor, holding ice, splashing water), mental (naming 5 things you see, 4 you hear, 3 you touch, 2 you smell, 1 you taste), soothing (self-talk, imagery, breathing). Used for: dissociation, flashbacks, panic attacks, emotional flooding, and anxiety. Teaching clients grounding skills is a core stabilization strategy in trauma treatment.", difficulty: 1, category: "Trauma-Informed Care", topic: "Grounding Techniques", questionType: "CASE_VIGNETTE" },
  { id: "sw-799", stem: "What is 'kinship care' and its advantages over non-relative foster care?", options: ["Care by strangers is always preferred", "Placement of children with relatives or individuals with a significant relationship to the child, which maintains family connections, cultural continuity, reduces placement trauma, and often provides greater stability than non-relative foster care", "It is the same as foster care", "Kinship care is less stable"], correctIndex: 1, rationale: "Kinship care benefits: maintains family and cultural connections, less traumatic for children, preserves sibling relationships, higher placement stability, greater sense of belonging, continuity of community and school, and children report feeling more loved and secure. Challenges include: less formal support and training for kinship caregivers, potential family dynamics issues, and financial strain. Social workers advocate for kinship caregiver support.", difficulty: 2, category: "Child & Family Services", topic: "Kinship Care", questionType: "CASE_VIGNETTE" },
  { id: "sw-800", stem: "A social worker notices that a client's needs would be better served by a different provider. The ethical obligation is to:", options: ["Continue providing services regardless", "Make an appropriate referral to ensure the client receives competent services while managing the transition carefully, including discussing reasons for the referral with the client and following up to ensure continuity of care", "Terminate without referral", "Tell the client they can't be helped"], correctIndex: 1, rationale: "The NASW Code of Ethics requires referring clients when: the social worker lacks competence in the needed area, another provider can better serve the client, or a conflict of interest exists. The referral process includes: discussing reasons with the client, obtaining consent, providing multiple referral options, facilitating the transition, transferring relevant information (with consent), and following up to ensure connection.", difficulty: 1, category: "Case Management", topic: "Ethical Referral", questionType: "PRIORITIZATION" },
  { id: "sw-801", stem: "What is the 'Housing First' model?", options: ["Housing is earned through compliance", "An approach that provides immediate, permanent housing to individuals experiencing homelessness without preconditions such as sobriety or treatment participation, based on the principle that housing is a basic need and right", "Temporary shelter programs", "Housing with mandatory treatment"], correctIndex: 1, rationale: "Housing First (Tsemberis, Pathways to Housing): immediate permanent housing without preconditions, voluntary supportive services, harm reduction approach, consumer choice, separation of housing from treatment. Evidence shows: higher housing retention, reduced emergency services use, cost-effective, improved quality of life. It challenges the traditional 'treatment first' or 'staircase' model that requires readiness before housing.", difficulty: 2, category: "Community Practice & Advocacy", topic: "Housing First", questionType: "MCQ" },
  { id: "sw-802", stem: "What is 'co-occurring disorders' (dual diagnosis) and why does it present treatment challenges?", options: ["Having two physical illnesses", "The simultaneous presence of a mental health disorder and a substance use disorder in an individual, requiring integrated treatment because each condition affects the course, prognosis, and treatment of the other", "Sequential treatment of separate disorders", "A rare occurrence"], correctIndex: 1, rationale: "Co-occurring disorders are common (approximately 50% of individuals with severe mental illness have substance use disorders). Treatment challenges: each condition worsens the other, traditional systems treat them separately, medication interactions, increased suicide risk, housing instability, and treatment dropout. Best practice: integrated treatment addressing both simultaneously, motivational approaches, harm reduction, and peer support.", difficulty: 2, category: "Addictions & Substance Use", topic: "Co-occurring Disorders", questionType: "CASE_VIGNETTE" },
  { id: "sw-803", stem: "What is the 'person-centered approach' to dementia care?", options: ["Focusing only on cognitive decline", "An approach developed by Tom Kitwood that recognizes the personhood of individuals with dementia, focuses on remaining abilities and strengths, respects preferences and life history, and creates environments that support well-being rather than just managing behaviors", "Only using medications to manage behaviors", "Institutionalizing all dementia patients"], correctIndex: 1, rationale: "Person-centered dementia care (Kitwood) emphasizes: maintaining personhood, understanding behavior as communication, using life history to guide care, creating supportive environments, building relationships, validating emotions, promoting choice and autonomy within safety limits, and supporting remaining abilities. It reduces: behavioral symptoms, medication use, caregiver stress, and improves quality of life for people with dementia.", difficulty: 2, category: "Gerontology", topic: "Person-Centered Dementia Care", questionType: "CASE_VIGNETTE" },
  { id: "sw-804", stem: "An ASWB exam question asks about 'dual relationships.' The BEST answer is:", options: ["Dual relationships are always acceptable", "Dual relationships occur when a social worker has a professional relationship and another type of relationship (personal, business, social) with the same person, and they should be avoided when there is a risk of exploitation or harm to the client", "Dual relationships only occur in rural areas", "All dual relationships must be reported"], correctIndex: 1, rationale: "Dual relationships are not automatically unethical but require careful management. The NASW Code of Ethics prohibits dual relationships that risk exploitation or harm. Considerations: power differential, potential for exploitation, cultural context (some communities make them unavoidable), and client vulnerability. In unavoidable situations (rural practice, small communities): set clear boundaries, document, consult, and prioritize client welfare.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "Dual Relationships", questionType: "MCQ" },
  { id: "sw-805", stem: "What is the 'window of tolerance' concept in trauma treatment?", options: ["A timeframe for treatment", "The optimal zone of emotional arousal within which a person can function effectively, process emotions, and engage in therapy, with hyperarousal (fight/flight) above and hypoarousal (freeze/collapse) below this window", "A type of exposure therapy", "The number of sessions needed for treatment"], correctIndex: 1, rationale: "The window of tolerance (Siegel) describes the optimal arousal zone: within the window, a person can think clearly, process emotions, and engage therapeutically. Above (hyperarousal): anxiety, panic, hypervigilance, rage. Below (hypoarousal): numbness, dissociation, collapse, shutdown. Trauma narrows the window. Treatment goals: expand the window, teach self-regulation skills, and pace therapeutic work to stay within the window.", difficulty: 2, category: "Trauma-Informed Care", topic: "Window of Tolerance", questionType: "CASE_VIGNETTE" },
  { id: "sw-806", stem: "What is the 'strengths perspective' in social work?", options: ["Ignoring problems and challenges", "A philosophical approach that focuses on identifying and building upon clients' existing strengths, resources, capabilities, and aspirations rather than solely focusing on deficits, problems, and pathology", "Only positive thinking", "Denying the reality of problems"], correctIndex: 1, rationale: "The strengths perspective (Saleebey) principles: every individual has strengths, motivation arises from emphasizing strengths, collaboration is essential, every environment has resources, and caring is essential. It doesn't ignore problems but reframes the approach: from 'what's wrong with you?' to 'what's strong with you?' It informs assessment, goal-setting, and intervention across all social work settings.", difficulty: 1, category: "Assessment & Intervention Planning", topic: "Strengths Perspective", questionType: "PRIORITIZATION" },
  { id: "sw-807", stem: "What is 'critical race theory' and its relevance to social work?", options: ["A theory that all white people are racist", "An analytical framework that examines how race and racism are embedded in legal systems, policies, and institutions, shaping unequal outcomes for people of color, and informing social work's commitment to anti-racist practice and structural change", "Only applicable to legal studies", "A partisan political ideology"], correctIndex: 1, rationale: "CRT (Delgado, Bell, Crenshaw) examines: how racism is embedded in systems rather than just individual attitudes, the role of law and policy in maintaining racial inequality, interest convergence, counter-narratives of people of color, and the permanence of racism in American society. For social work, CRT informs: anti-racist practice, policy advocacy, critical self-reflection, and understanding structural determinants of health disparities.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "Critical Race Theory", questionType: "CASE_VIGNETTE" },
  { id: "sw-808", stem: "What is a 'genogram' and how is it used in social work assessment?", options: ["A genetic test", "A visual diagram of a family's intergenerational relationships, patterns, and significant events that provides a comprehensive picture of family structure, dynamics, medical history, behavioral patterns, and relationships across at least three generations", "A geographic map", "A treatment timeline"], correctIndex: 1, rationale: "Genograms use standardized symbols to map: family structure (marriages, divorces, births, deaths), relationship patterns (close, conflictual, distant, enmeshed), intergenerational patterns (addiction, mental illness, abuse, resilience), medical history, and cultural/social factors. They help clinicians: identify patterns, engage families, generate hypotheses, plan interventions, and understand the client within their family context.", difficulty: 1, category: "Assessment & Intervention Planning", topic: "Genogram", questionType: "PRIORITIZATION" },
  { id: "sw-809", stem: "What is 'harm reduction' in the context of substance use treatment?", options: ["Encouraging drug use", "A pragmatic public health approach that aims to reduce the negative consequences of substance use without requiring abstinence, meeting people where they are and prioritizing incremental improvements in health and safety", "The same as abstinence-based treatment", "Only needle exchange programs"], correctIndex: 1, rationale: "Harm reduction strategies include: needle exchange programs, naloxone distribution, medication-assisted treatment, safe consumption sites, drug checking services, education about safer use, and outreach services. Principles: pragmatism over idealism, respect for autonomy, incremental change, meeting people where they are, and recognizing substance use exists on a continuum. It complements rather than opposes abstinence-based approaches.", difficulty: 2, category: "Addictions & Substance Use", topic: "Harm Reduction", questionType: "CASE_VIGNETTE" },
  { id: "sw-810", stem: "What is 'therapeutic alliance' and why is it important?", options: ["A professional organization", "The collaborative, trusting relationship between the therapist and client, which research consistently identifies as one of the strongest predictors of positive treatment outcomes across all therapeutic modalities", "Only important in long-term therapy", "The therapist's theoretical orientation"], correctIndex: 1, rationale: "Therapeutic alliance (Bordin) consists of: agreement on goals, agreement on tasks, and the bond between therapist and client. Research shows alliance accounts for more outcome variance than specific therapeutic techniques. Alliance is strengthened by: empathy, genuineness, positive regard, collaboration, cultural responsiveness, and alliance rupture-repair. Social workers develop alliance skills through training, supervision, and self-awareness.", difficulty: 1, category: "Communication & Interviewing", topic: "Therapeutic Alliance", questionType: "CASE_VIGNETTE" },
  { id: "sw-811", stem: "What is 'social learning theory' and its application in social work?", options: ["Only classroom learning", "Bandura's theory that behavior is learned through observation, imitation, and modeling within social contexts, with key concepts including observational learning, self-efficacy, and reciprocal determinism between behavior, cognition, and environment", "Only operant conditioning", "A theory about social media"], correctIndex: 1, rationale: "Social learning theory (Bandura) explains behavior through: observational learning (modeling), vicarious reinforcement/punishment, self-efficacy beliefs, and reciprocal determinism (behavior, personal factors, and environment interact). Applications in social work: parent training (modeling appropriate behavior), group therapy (peer modeling), violence prevention (examining media influences), and building self-efficacy through mastery experiences.", difficulty: 2, category: "Clinical Practice", topic: "Social Learning Theory", questionType: "CASE_VIGNETTE" },
  { id: "sw-812", stem: "What are the ethical considerations around client record access?", options: ["Clients have no right to their records", "Clients generally have the right to access their records, and social workers must provide access while protecting any information that could cause serious harm, maintaining records in compliance with applicable laws and ethical standards", "Records belong solely to the agency", "Only courts can access records"], correctIndex: 1, rationale: "NASW Code of Ethics and HIPAA provide clients the right to access their records. Considerations: the right is not absolute (information that could cause serious harm may be withheld), records should be maintained accurately, clients can request amendments, access procedures should be clear, and records should be written with the assumption that clients will read them. Social workers should document with care, objectivity, and respect.", difficulty: 2, category: "Documentation & Record Keeping", topic: "Record Access", questionType: "MCQ" },
  { id: "sw-813", stem: "What is 'restorative justice' and how is it applied in school settings?", options: ["Punitive discipline", "An approach that responds to wrongdoing by focusing on repairing harm done to relationships and community through inclusive processes like circles, conferencing, and mediation, rather than relying solely on punishment", "Only for criminal offenses", "Ignoring misbehavior"], correctIndex: 1, rationale: "Restorative justice in schools: circles (building community and addressing harm), conferencing (involving all affected parties), peer mediation, and restorative conversations. Benefits: reduces suspensions and expulsions, improves school climate, addresses racial discipline disparities, teaches accountability and empathy, and repairs relationships. It shifts from 'what rule was broken and what punishment is deserved' to 'who was harmed and how can we repair it.'", difficulty: 2, category: "School Social Work", topic: "Restorative Justice", questionType: "MCQ" },
  { id: "sw-814", stem: "What is 'guardianship' and when is it appropriate?", options: ["Automatic for all elderly people", "A legal process in which a court appoints a person to make decisions for an individual who has been determined to lack the capacity to make decisions for themselves, used as a last resort when less restrictive alternatives are insufficient", "The same as power of attorney", "A voluntary arrangement"], correctIndex: 1, rationale: "Guardianship involves: court determination of incapacity, appointment of a guardian, and transfer of decision-making authority. Types: full (all decisions) or limited (specific domains). It should be: a last resort after less restrictive alternatives are exhausted (supported decision-making, representative payee, power of attorney), proportionate, and regularly reviewed. Social workers advocate for the least restrictive option that protects the individual.", difficulty: 2, category: "Safeguarding & Vulnerable Populations", topic: "Guardianship", questionType: "PRIORITIZATION" },
  { id: "sw-815", stem: "What is the 'digital divide' and its impact as a social determinant of health?", options: ["A type of technology", "The gap between those who have access to digital technology and the internet and those who do not, which creates disparities in healthcare access, health information, telehealth services, employment, education, and social connection", "Only affects older adults", "Not related to health outcomes"], correctIndex: 1, rationale: "The digital divide impacts: telehealth access (critical during pandemics), patient portal use, health information access, online appointment scheduling, employment opportunities, educational resources, social connection, and government service access. Disparities disproportionately affect: low-income, rural, elderly, disabled, and racial minority populations. Social workers advocate for digital equity, digital literacy programs, and alternative service delivery.", difficulty: 2, category: "Social Determinants of Health", topic: "Digital Divide", questionType: "MCQ" },
  { id: "sw-816", stem: "What is 'social work supervision' and its three primary functions?", options: ["Only administrative oversight", "A professional relationship that serves three functions: administrative (ensuring quality and compliance), educational (developing clinical skills and knowledge), and supportive (addressing emotional impact of the work and preventing burnout)", "Only clinical training", "Performance evaluation only"], correctIndex: 1, rationale: "Social work supervision (Kadushin): administrative (assigning work, reviewing performance, ensuring compliance), educational (teaching skills, promoting critical thinking, case conceptualization), and supportive (processing emotional responses, preventing burnout, building confidence). Effective supervision requires: regular scheduled meetings, a safe learning environment, appropriate modeling, cultural responsiveness, and attention to supervisee development.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "Supervision Functions", questionType: "MCQ" },
  { id: "sw-817", stem: "An ASWB exam question asks about the concept of 'regression.' This refers to:", options: ["Moving forward in treatment", "A defense mechanism in which an individual reverts to behaviors characteristic of an earlier developmental stage in response to stress, anxiety, or overwhelming situations", "A statistical method", "Progressive muscle relaxation"], correctIndex: 1, rationale: "Regression is a defense mechanism where stress triggers return to earlier developmental behaviors: an adult throwing tantrums, a toilet-trained child wetting the bed during family crisis, or a hospitalized patient becoming dependent. It is common during: illness, hospitalization, significant life changes, trauma, and periods of heightened anxiety. Social workers normalize regression while supporting return to age-appropriate functioning.", difficulty: 1, category: "Exam-Style Mixed Practice", topic: "Regression", questionType: "MCQ" },
  { id: "sw-818", stem: "What is the social worker's role in supporting LGBTQ+ youth?", options: ["Attempting to change sexual orientation or gender identity", "Providing affirming services, understanding unique stressors (minority stress, family rejection, bullying), advocating for inclusive policies, connecting to supportive resources, and addressing higher rates of depression, anxiety, homelessness, and suicidality in this population", "Referring to conversion therapy", "Treating LGBTQ+ identity as pathology"], correctIndex: 1, rationale: "LGBTQ+ youth face unique challenges: family rejection (40% of homeless youth are LGBTQ+), bullying, minority stress, internalized stigma, and elevated rates of depression, anxiety, substance use, and suicidality. Affirming practice includes: using correct names/pronouns, validating identity, providing LGBTQ+-competent services, connecting to affirming communities, advocating for inclusive school policies, and opposing conversion therapy (which is harmful and unethical).", difficulty: 2, category: "Diversity, Equity & Inclusion", topic: "LGBTQ+ Youth", questionType: "CASE_VIGNETTE" },
  { id: "sw-819", stem: "What is 'therapeutic foster care' (treatment foster care)?", options: ["Regular foster care", "A specialized foster care model where children with significant emotional, behavioral, or mental health needs are placed with specially trained foster parents who provide a therapeutic environment as part of a comprehensive treatment plan", "Institutional care", "Only for children with physical disabilities"], correctIndex: 1, rationale: "Therapeutic foster care (e.g., MTFC/Multidimensional Treatment Foster Care): specially trained foster parents, small caseloads, intensive support, behavioral management system, individual therapy for the child, family therapy with biological family, school consultation, and 24/7 support for foster parents. Evidence shows: reduced behavioral problems, improved placement stability, better outcomes than group residential care, and support for eventual reunification.", difficulty: 2, category: "Child & Family Services", topic: "Therapeutic Foster Care", questionType: "CASE_VIGNETTE" },
  { id: "sw-820", stem: "What is 'trauma-focused cognitive behavioral therapy' (TF-CBT)?", options: ["General CBT applied to trauma", "An evidence-based treatment model for children and adolescents affected by trauma that includes components: psychoeducation, relaxation, affective modulation, cognitive coping, trauma narrative, in vivo mastery, conjoint parent-child sessions, and enhancing safety", "Only for adults with PTSD", "A medication-based treatment"], correctIndex: 1, rationale: "TF-CBT (Cohen, Mannarino, Deblinger) uses the PRACTICE acronym: Psychoeducation, Relaxation, Affective modulation, Cognitive coping, Trauma narrative, In vivo mastery, Conjoint sessions, Enhancing safety. It is evidence-based for ages 3-18, includes caregiver involvement throughout, addresses both the child's and caregiver's trauma reactions, and has strong evidence for sexual abuse, domestic violence, traumatic grief, and other traumas.", difficulty: 2, category: "Trauma-Informed Care", topic: "TF-CBT", questionType: "CASE_VIGNETTE" },
  { id: "sw-821", stem: "What does 'least restrictive environment' mean in special education?", options: ["Removing all structure", "Students with disabilities should be educated with non-disabled peers to the maximum extent appropriate, with supplementary aids and services provided to support inclusion before considering more restrictive placements", "Separate classrooms for all disabled students", "Only mainstream placement"], correctIndex: 1, rationale: "Least restrictive environment (LRE) is an IDEA principle: children with disabilities should be educated with non-disabled peers to the maximum extent appropriate. The continuum ranges from full inclusion to homebound instruction, with placement determined by IEP team based on individual needs. Removal from general education occurs only when education cannot be achieved satisfactorily with supplementary aids and services.", difficulty: 2, category: "School Social Work", topic: "Least Restrictive Environment", questionType: "MCQ" },
  { id: "sw-822", stem: "What is 'ACEs' (Adverse Childhood Experiences) research and its significance?", options: ["A study about academic achievement", "Landmark research demonstrating a dose-response relationship between the number of adverse childhood experiences (abuse, neglect, household dysfunction) and increased risk for chronic disease, mental illness, substance use, and early death in adulthood", "Only about child abuse", "Research that has been discredited"], correctIndex: 1, rationale: "ACEs research (Felitti, Anda): 10 categories of childhood adversity: abuse (physical, emotional, sexual), neglect (physical, emotional), household dysfunction (domestic violence, substance use, mental illness, incarceration, divorce). Higher ACE scores correlate with: increased chronic disease risk, mental health disorders, substance use, risky behaviors, and early death. ACE-informed practice: routine screening, trauma-informed approaches, building resilience, and preventing ACEs.", difficulty: 2, category: "Assessment & Intervention Planning", topic: "ACEs Research", questionType: "PRIORITIZATION" },
  { id: "sw-823", stem: "What is 'progressive muscle relaxation' (PMR) and when is it used?", options: ["Intense physical exercise", "A stress management technique that involves systematically tensing and then releasing different muscle groups throughout the body to reduce physical tension, decrease anxiety, and promote relaxation", "Only for athletes", "A form of psychotherapy"], correctIndex: 1, rationale: "PMR (Jacobson) involves: sequentially tensing muscle groups for 5-10 seconds, then releasing for 15-20 seconds, progressing through the body. Benefits: reduces physiological arousal, decreases anxiety, improves sleep, and increases body awareness. Used for: anxiety disorders, insomnia, chronic pain, PTSD, and stress management. Social workers teach PMR as a coping skill that clients can use independently.", difficulty: 1, category: "Clinical Practice", topic: "Progressive Muscle Relaxation", questionType: "CASE_VIGNETTE" },
  { id: "sw-824", stem: "What is 'critical incident stress debriefing' (CISD) and what is the current evidence?", options: ["Always effective after trauma", "A structured group intervention originally used after critical incidents, which current evidence suggests may not prevent PTSD and could potentially be harmful for some participants, leading to a shift toward psychological first aid approaches", "The gold standard for trauma intervention", "Only for military personnel"], correctIndex: 1, rationale: "CISD (Mitchell) is a structured group debriefing after critical incidents. However, current evidence: does not support mandatory debriefing for all exposed individuals, some studies suggest potential for harm (re-traumatization, impeding natural recovery), and single-session debriefing is insufficient. Current best practice: Psychological First Aid (PFA), which emphasizes safety, calming, self-efficacy, connectedness, and hope without requiring detailed event processing.", difficulty: 3, category: "Crisis Intervention", topic: "CISD Evidence", questionType: "CASE_VIGNETTE" },
  { id: "sw-825", stem: "What is 'cultural humility' and how does it differ from 'cultural competence'?", options: ["They are identical concepts", "Cultural humility is an ongoing process of self-reflection, recognizing power imbalances, and approaching each client as the expert on their own cultural experience, while cultural competence implies a finite endpoint of mastering knowledge about specific cultures", "Cultural humility is less important", "Cultural competence is more current"], correctIndex: 1, rationale: "Cultural humility (Tervalon & Murray-Garcia): lifelong learning and critical self-reflection, recognition of power dynamics in helping relationships, institutional accountability, and approaching each encounter with openness. Cultural competence suggests an achievable endpoint of cultural knowledge. Cultural humility is preferred because: culture is complex and individual, no one can fully master another's culture, and the client is the expert on their own experience.", difficulty: 2, category: "Diversity, Equity & Inclusion", topic: "Cultural Humility", questionType: "CASE_VIGNETTE" },
];
